import React, { useRef, useEffect, useState } from "react";

/**
 * VideoPlayer — shared video component with:
 * - Dual <source> elements (WebM preferred, MP4 fallback) for browser format negotiation
 * - IntersectionObserver-based autoplay: only plays when the element is visible
 * - preload="metadata" by default: fetches only duration/dimensions, not the full file
 * - Error fallback with configurable placeholder content
 * - Consistent attributes for autoplay, mute, loop, playsInline across all browsers
 *
 * Props:
 *   mp4        {string}  URL of the MP4 source (required if no webm)
 *   webm       {string}  URL of the WebM source (optional but preferred if available)
 *   autoPlay   {bool}    Whether to autoplay when visible (default: true)
 *   muted      {bool}    Whether to mute (default: true — required for autoplay in most browsers)
 *   loop       {bool}    Whether to loop (default: true)
 *   className  {string}  CSS class(es) for the <video> element
 *   style      {object}  Inline styles for the <video> element
 *   controls   {bool}    Whether to show browser controls (default: false)
 *   poster     {string}  URL of poster frame image
 *   onLoaded   {func}    Callback when video data has loaded
 *   videoRef   {ref}     Optional external ref to access the video element
 *   fallback   {node}    Custom fallback content when video fails to load
 *   threshold  {number}  IntersectionObserver threshold for triggering play (default: 0.3)
 */
const VideoPlayer = ({
  mp4,
  webm,
  autoPlay = true,
  muted = true,
  loop = true,
  className = "",
  style = {},
  controls = false,
  poster,
  onLoaded,
  videoRef: externalRef,
  fallback,
  threshold = 0.3,
  ...rest
}) => {
  const internalRef = useRef(null);
  const videoRef = externalRef || internalRef;
  const [hasError, setHasError] = useState(false);

  useEffect(() => {
    if (!autoPlay) return;
    const video = videoRef.current;
    if (!video) return;

    let observer;
    try {
      observer = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.isIntersecting) {
              // Ensure muted before playing (required for autoplay policy)
              video.muted = true;
              const playPromise = video.play();
              if (playPromise !== undefined) {
                playPromise.catch(() => {
                  // Autoplay blocked — attempt again after short delay
                  setTimeout(() => {
                    video.play().catch(() => {});
                  }, 200);
                });
              }
            } else {
              // Pause when out of view to save CPU/bandwidth
              video.pause();
            }
          });
        },
        { threshold }
      );
      observer.observe(video);
    } catch (e) {
      // IntersectionObserver not supported — fall back to direct play
      if (autoPlay) {
        video.muted = true;
        video.play().catch(() => {});
      }
    }

    return () => {
      if (observer) observer.disconnect();
    };
  }, [autoPlay, threshold, videoRef]);

  if (hasError) {
    return (
      fallback || (
        <div
          className={className}
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            backgroundColor: "var(--bg-secondary, #e9ecef)",
            aspectRatio: "16/9",
            borderRadius: "8px",
            color: "var(--text-dark-secondary, #6c757d)",
            fontSize: "0.85rem",
            textAlign: "center",
            padding: "16px",
            ...style,
          }}
        >
          <span>🎬 Video preview unavailable</span>
        </div>
      )
    );
  }

  return (
    <video
      ref={videoRef}
      className={className}
      style={style}
      muted={muted}
      loop={loop}
      playsInline
      preload="metadata"
      controls={controls}
      poster={poster}
      disablePictureInPicture
      onLoadedData={onLoaded}
      onError={() => setHasError(true)}
      {...rest}
    >
      {webm && <source src={webm} type="video/webm" />}
      {mp4 && <source src={mp4} type="video/mp4" />}
    </video>
  );
};

export default VideoPlayer;
