import React from "react"
import Fade from "./animations/Fade"
import { useLanguage } from "../contexts/LanguageContext"
import data, { getText } from "../data"
import { StaticImage } from "gatsby-plugin-image"
import "../styles/about.scss"

const About = () => {
  const { language } = useLanguage();
  return (
    <div className="section" id="about">
      <div className="container">
        <Fade bottom cascade distance="20px">
          <h1>{getText(data.sections.about, language)}</h1>
          <h3 className="section-subheading text-muted" style={{
            fontFamily: '"Droid Serif", "Helvetica Neue", Helvetica, Arial, sans-serif',
            fontStyle: 'italic',
            fontSize: '1rem',
            marginBottom: '40px',
            textAlign: 'center'
          }}>
            {getText(data.aboutSubtitle, language)}
          </h3>
        </Fade>
        <div className="about-section">
          <div className="content">
            <Fade bottom distance="20px">
              <p dangerouslySetInnerHTML={{ __html: getText(data.aboutParaOne, language) }}></p>
              <p dangerouslySetInnerHTML={{ __html: getText(data.aboutParaTwo, language) }}></p>
              <p dangerouslySetInnerHTML={{ __html: getText(data.aboutParaThree, language) }}></p>
            </Fade>
          </div>
          <Fade bottom duration={1000} distance="20px">
            <div className="image-container">
              <StaticImage
                src="../images/SelfPhoto4.webp"
                alt="Julius Chen"
                placeholder="blurred"
                layout="constrained"
                width={800}
                formats={["auto", "webp", "avif"]}
                quality={80}
                className="img-fluid"
              />
            </div>
          </Fade>
        </div>
      </div>
    </div>
  )
}

export default About
